const rows = $input.all();

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function removeAccents(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function slug(value) {
  return removeAccents(value)
    .replace(/\s+/g, "_")
    .replace(/-+/g, "_")
    .replace(/_+/g, "_")
    .trim();
}

function isBlankRow(row) {
  return Object.values(row || {}).every(v => clean(v) === "");
}

function normalizeBool(value, defaultValue = true) {
  if (typeof value === "boolean") return value;

  const v = removeAccents(value);

  if (["sim", "s", "yes", "y", "true", "1", "ativo"].includes(v)) return true;
  if (["nao", "n", "no", "false", "0", "inativo"].includes(v)) return false;

  return defaultValue;
}

function normalizeDate(value) {
  if (value === null || value === undefined || value === "") return "";

  if (value instanceof Date && !isNaN(value)) {
    return value.toISOString().slice(0, 10);
  }

  const raw = clean(value);

  // yyyy-mm-dd ou yyyy-mm-ddTHH:mm:ss
  if (/^\d{4}-\d{2}-\d{2}/.test(raw)) {
    return raw.slice(0, 10);
  }

  // dd/mm/yyyy
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(raw)) {
    const [dd, mm, yyyy] = raw.split("/");
    return `${yyyy}-${mm}-${dd}`;
  }

  // dd-mm-yyyy
  if (/^\d{2}-\d{2}-\d{4}$/.test(raw)) {
    const [dd, mm, yyyy] = raw.split("-");
    return `${yyyy}-${mm}-${dd}`;
  }

  // Google Sheets serial date
  // Base correta: 1899-12-30
  if (/^\d+(\.\d+)?$/.test(raw)) {
    const serial = Number(raw);
    if (serial > 20000 && serial < 80000) {
      const date = new Date(Date.UTC(1899, 11, 30) + serial * 86400000);
      return date.toISOString().slice(0, 10);
    }
  }

  return "";
}

function normalizeTipoPeriodo(value) {
  const v = slug(value);

  const map = {
    feriado: "feriado",
    feriados: "feriado",

    alta: "alta_temporada",
    alta_temporada: "alta_temporada",
    temporada_alta: "alta_temporada",

    baixa: "baixa_temporada",
    baixa_temporada: "baixa_temporada",
    temporada_baixa: "baixa_temporada",

    bloqueio: "bloqueio",
    bloqueado: "bloqueio",

    especial: "periodo_especial",
    periodo_especial: "periodo_especial",
    evento_especial: "periodo_especial"
  };

  return map[v] || "periodo_especial";
}

function normalizeUnidade(value) {
  const v = slug(value);

  const map = {
    ambas: "ambas",
    todos: "ambas",
    todas: "ambas",
    geral: "ambas",

    auau: "auau",
    au_au: "auau",
    amaralina: "auau",
    auau_amaralina: "auau",

    auauzin: "auauzin",
    auau_zin: "auauzin",
    au_auzin: "auauzin",
    patamares: "auauzin",
    auauzin_patamares: "auauzin"
  };

  return map[v] || "ambas";
}

function normalizeTarifaHotel(value) {
  const v = slug(value);

  const map = {
    normal: "normal",
    padrao: "normal",
    diaria_normal: "normal",

    baixa: "baixa",
    baixa_temporada: "baixa",
    temporada_baixa: "baixa",

    alta: "alta",
    alta_temporada: "alta",
    temporada_alta: "alta"
  };

  return map[v] || "normal";
}

function sqlText(value) {
  return `'${clean(value).replace(/'/g, "''")}'`;
}

function sqlDate(value) {
  return `'${clean(value)}'::date`;
}

function sqlBool(value) {
  return value === true ? "true" : "false";
}

function sqlBigintOrNull(value) {
  const v = clean(value);
  if (!v || ["null", "undefined", "nan"].includes(v.toLowerCase())) return "null";

  const onlyNumber = v.replace(/[^\d]/g, "");
  return onlyNumber ? `${onlyNumber}::bigint` : "null";
}

const output = [];
const errors = [];

rows.forEach((item, index) => {
  const row = item.json || {};

  if (isBlankRow(row)) return;

  const rowNumber =
    row.row_number ||
    row.rowNumber ||
    row.__row_number ||
    index + 2;

  const id = clean(row.id);

  const titulo = clean(row.titulo);
  const tipoPeriodo = normalizeTipoPeriodo(row.tipo_periodo);
  const unidade = normalizeUnidade(row.unidade);

  const dataInicio = normalizeDate(row.data_inicio);
  const dataFim = normalizeDate(row.data_fim || row.data_inicio);

  const permiteAvaliacao = normalizeBool(row.permite_avaliacao, true);
  const permiteCheckin = normalizeBool(row.permite_checkin, true);
  const permiteCheckout = normalizeBool(row.permite_checkout, true);

  const tarifaHotel = normalizeTarifaHotel(row.tarifa_hotel);
  const observacoes = clean(row.observacoes);
  const ativo = normalizeBool(row.ativo, true);

  const camposFaltando = [];

  if (!titulo) camposFaltando.push("titulo");
  if (!dataInicio) camposFaltando.push("data_inicio");
  if (!dataFim) camposFaltando.push("data_fim");

  if (camposFaltando.length > 0) {
    errors.push(`Linha ${rowNumber}: campos obrigatórios ausentes ou inválidos: ${camposFaltando.join(", ")}`);
    return;
  }

  const upsertSql = `
    insert into public.bruna_calendario_operacional (
      titulo,
      tipo_periodo,
      unidade,
      data_inicio,
      data_fim,
      permite_avaliacao,
      permite_checkin,
      permite_checkout,
      tarifa_hotel,
      observacoes,
      ativo,
      criado_em,
      atualizado_em
    )
    values (
      ${sqlText(titulo)},
      ${sqlText(tipoPeriodo)},
      ${sqlText(unidade)},
      ${sqlDate(dataInicio)},
      ${sqlDate(dataFim)},
      ${sqlBool(permiteAvaliacao)},
      ${sqlBool(permiteCheckin)},
      ${sqlBool(permiteCheckout)},
      ${sqlText(tarifaHotel)},
      ${sqlText(observacoes)},
      ${sqlBool(ativo)},
      now(),
      now()
    )
    on conflict (
      titulo,
      tipo_periodo,
      unidade,
      data_inicio,
      data_fim
    )
    do update set
      permite_avaliacao = excluded.permite_avaliacao,
      permite_checkin = excluded.permite_checkin,
      permite_checkout = excluded.permite_checkout,
      tarifa_hotel = excluded.tarifa_hotel,
      observacoes = excluded.observacoes,
      ativo = excluded.ativo,
      atualizado_em = now()
    returning *, ${Number(rowNumber)} as sheet_row_number;
    `.trim();

  output.push({
    json: {
      id: id || null,
      titulo,
      tipo_periodo: tipoPeriodo,
      unidade,
      data_inicio: dataInicio,
      data_fim: dataFim,
      permite_avaliacao: permiteAvaliacao,
      permite_checkin: permiteCheckin,
      permite_checkout: permiteCheckout,
      tarifa_hotel: tarifaHotel,
      observacoes,
      ativo,
      row_number: rowNumber,
      upsert_sql: upsertSql
    }
  });
});

if (errors.length > 0) {
  throw new Error(`Erro ao normalizar calendário:\n${errors.join("\n")}`);
}

return output;
